+import { AccountSummary } from '@domain/account_summary';
+import NumberFlow from '@number-flow/react';
+import { useAuthStore } from '@state/authStore/useAuthStore';
+import { PiggyBankIcon } from '@ui/assets/icons/PiggyBankIcon';
+import { parseISO, startOfMonth } from 'date-fns';
+import { utcToZonedTime } from 'date-fns-tz';
+import { useMemo } from 'react';
+import { MetricsCard, MetricsGrid, MonthlyRevenueChart, RevenueSourcesChart } from './components';
+import { useDashboardData } from './hooks/useDashboardData';
+import './Dashboard.css';
+
+const getTimeOfDayGreeting = (): string => {
+  const hour = new Date().getHours();
+  if (hour < 12) {
+    return 'Good morning';
+  } else if (hour < 17) {
+    return 'Good afternoon';
+  } else {
+    return 'Good evening';
+  }
+};
+
+const calculateMonthlyChange = (
+  summary: AccountSummary,
+  field: 'revenue' | 'donations' | 'donors'
+): number => {
+  const monthly = summary?.intervals?.monthly || [];
+  if (monthly.length < 2) {
+    return 0;
+  }
+
+  // Sort by date (most recent last)
+  const sortedMonthly = [...monthly].sort((a, b) => {
+    const aDate = parseISO(a.month);
+    const bDate = parseISO(b.month);
+    return aDate.getTime() - bDate.getTime();
+  });
+
+  // Get the most recent month (last in sorted array)
+  const currentMonthData = sortedMonthly[sortedMonthly.length - 1];
+  // Get the previous month (second to last)
+  const previousMonthData = sortedMonthly[sortedMonthly.length - 2];
+
+  if (!currentMonthData || !previousMonthData) {
+    return 0;
+  }
+
+  const currentValue = currentMonthData[field] || 0;
+  const previousValue = previousMonthData[field] || 0;
+
+  // If previous value is 0, handle infinite change based on direction
+  if (previousValue === 0) {
+    if (currentValue > 0) {
+      return Infinity; // Infinite increase (going from 0 to positive)
+    } else if (currentValue < 0) {
+      return -Infinity; // Infinite decrease (going from 0 to negative)
+    }
+    return 0; // Both are 0, no change
+  }
+
+  return ((currentValue - previousValue) / previousValue) * 100;
+};
+
+export const Dashboard = () => {
+  const { data: summary, isLoading } = useDashboardData();
+  const { user } = useAuthStore();
+  const greeting = getTimeOfDayGreeting();
+  const userName = user?.firstName || 'there';
+
+  // Calculate monthly changes
+  const revenueChange = useMemo(
+    () => (summary ? calculateMonthlyChange(summary, 'revenue') : 0),
+    [summary]
+  );
+  const donationsChange = useMemo(
+    () => (summary ? calculateMonthlyChange(summary, 'donations') : 0),
+    [summary]
+  );
+  const donorsChange = useMemo(
+    () => (summary ? calculateMonthlyChange(summary, 'donors') : 0),
+    [summary]
+  );
+
+  if (isLoading) {
+    return (
+      <div className="p-6">
+        <div className="text-neutral-600">Loading...</div>
+      </div>
+    );
+  }
+
+  if (!summary) {
+    return (
+      <div className="p-6">
+        <div className="text-neutral-600">No data available</div>
+      </div>
+    );
+  }
+
+  return (
+    <div className="flex flex-col gap-8 min-h-0 h-full w-full overflow-y-auto bg-neutral-200 p-6">
+      {/* Header with Balance */}
+      <div className="flex items-center justify-between">
+        <h1 className="text-3xl font-semibold text-neutral-700">
+          {greeting}, {userName}!
+        </h1>
+        <div className="flex items-center gap-2 text-xl">
+          <PiggyBankIcon className="w-6 h-6 text-green-500" />
+          <div className="text-lg text-neutral-700">
+            <span className="text-neutral-700 font-medium">Balance:</span>{' '}
+            <NumberFlow
+              value={(summary.balance || 0) / 100}
+              format={{
+                style: 'currency',
+                currency: 'USD',
+                minimumFractionDigits: 2,
+                maximumFractionDigits: 2,
+              }}
+            />
+          </div>
+        </div>
+      </div>
+
+      {/* All Time Metrics */}
+      <MetricsGrid title="All Time">
+        {[
+          {
+            title: 'Total Revenue',
+            value: (summary.totalRevenue || 0) / 100,
+            valueFormat: {
+              style: 'currency' as const,
+              currency: 'USD',
+              minimumFractionDigits: 2,
+              maximumFractionDigits: 2,
+            },
+          },
+          {
+            title: 'Total Donations',
+            value: summary.totalDonations || 0,
+            valueFormat: { useGrouping: true },
+          },
+          {
+            title: 'Total Donors',
+            value: summary.totalDonors || 0,
+            valueFormat: { useGrouping: true },
+          },
+          {
+            title: 'Total Contacts',
+            value: summary.totalContacts || 0,
+            valueFormat: { useGrouping: true },
+          },
+        ].map((metric) => (
+          <MetricsCard key={metric.title} {...metric} />
+        ))}
+      </MetricsGrid>
+
+      {/* This Month Metrics */}
+      <MetricsGrid title="This Month">
+        {[
+          {
+            title: 'Revenue',
+            value: (summary.monthRevenue || 0) / 100,
+            valueFormat: {
+              style: 'currency' as const,
+              currency: 'USD',
+              minimumFractionDigits: 2,
+              maximumFractionDigits: 2,
+            },
+            change: revenueChange,
+          },
+          {
+            title: 'Donations',
+            value: summary.monthDonations || 0,
+            valueFormat: { useGrouping: true },
+            change: donationsChange,
+          },
+          {
+            title: 'Donors',
+            value: summary.monthDonors || 0,
+            valueFormat: { useGrouping: true },
+            change: donorsChange,
+          },
+        ].map((metric) => (
+          <MetricsCard
+            key={metric.title}
+            title={metric.title}
+            value={metric.value}
+            valueFormat={metric.valueFormat}
+            changePercentage={metric.change}
+          />
+        ))}
+        <RevenueSourcesChart summary={summary} />
+      </MetricsGrid>
+      <MonthlyRevenueChart summary={summary} />
+    </div>
+  );
+};
+
+export default Dashboard;
