+import NumberFlow from '@number-flow/react';
+import { ChevronDownIcon } from '@ui/assets/icons/ChevronDownIcon';
+import { ChevronRightIcon } from '@ui/assets/icons/ChevronRightIcon';
+import { ChevronUpIcon } from '@ui/assets/icons/ChevronUpIcon';
+import { CircleIcon } from '@ui/assets/icons/CircleIcon';
+import { Card } from './Card';
+
+type MetricsCardProps = {
+  title: string;
+  value: number;
+  valueFormat?: Intl.NumberFormatOptions;
+  changePercentage?: number;
+  trendText?: string;
+  trendDirection?: 'up' | 'down';
+};
+
+const renderTrendIcon = (
+  hasTrendText: boolean,
+  changePercent: number | undefined,
+  direction: 'up' | 'down',
+  isTrivialChange: boolean
+) => {
+  if (!hasTrendText) {
+    return null;
+  }
+  if (changePercent === 0) {
+    return <CircleIcon className="flex-shrink-0 text-neutral-400" boxSize="12px" />;
+  }
+  if (isTrivialChange) {
+    return <ChevronRightIcon className="flex-shrink-0 text-neutral-600" />;
+  }
+  return direction === 'up' ? <ChevronUpIcon /> : <ChevronDownIcon />;
+};
+
+export const MetricsCard = ({ title, value, valueFormat, changePercentage }: MetricsCardProps) => {
+  // Determine trend direction based on sign of changePercentage
+  // Negative values indicate a decrease, positive values indicate an increase
+  const isTrendingUp = changePercentage !== undefined && changePercentage >= 0;
+  const trendDirection: 'up' | 'down' = isTrendingUp ? 'up' : 'down';
+
+  // Check if this is an infinite change (going from 0 to non-zero)
+  // Check for Infinity or -Infinity (non-finite values)
+  const isInfiniteChange =
+    changePercentage !== undefined &&
+    typeof changePercentage === 'number' &&
+    !isFinite(changePercentage);
+
+  // Determine if infinite change is an increase (Infinity) or decrease (-Infinity)
+  const isInfiniteIncrease = isInfiniteChange && changePercentage === Infinity;
+
+  // Only show change if it's defined and greater than 0.1% (absolute value) to avoid showing 0% changes
+  const displayChange =
+    changePercentage !== undefined && !isInfiniteChange && Math.abs(changePercentage) > 0.1
+      ? Math.abs(changePercentage)
+      : null;
+
+  // Determine if change is trivial (defined but very small)
+  const isTrivialChange =
+    changePercentage !== undefined &&
+    !isInfiniteChange &&
+    Math.abs(changePercentage) <= 0.1 &&
+    changePercentage !== 0;
+
+  // Determine trend text internally - handle all cases including 0 change, trivial change, and negative changes
+  const displayTrendText =
+    (changePercentage === 0 ? 'No change this month' : undefined) ||
+    (isTrivialChange ? 'No significant change this month' : undefined) ||
+    (isInfiniteChange || (changePercentage !== undefined && Math.abs(changePercentage) > 0.1)
+      ? `Trending ${trendDirection} this month`
+      : undefined);
+
+  // Badge content and visibility
+  // For negative values, show the negative sign; for positive values, show positive sign
+  // Only show "New" badge for infinite increases (0 to positive), not for infinite decreases
+  const badgeContent = isInfiniteIncrease
+    ? 'New'
+    : displayChange !== null && changePercentage !== undefined
+      ? `${changePercentage >= 0 ? '+' : ''}${changePercentage.toFixed(1)}%`
+      : null;
+
+  const badgeClassName = `absolute top-3 right-3 flex items-center gap-1 px-1.5 py-1 rounded-full border border-neutral-300 ${
+    isTrendingUp ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'
+  }`;
+
+  return (
+    <Card title={title} className="min-h-[120px]">
+      <div className="flex flex-col gap-2 justify-between h-full">
+        {/* Percentage badge - absolutely positioned */}
+        {badgeContent && (
+          <div className={badgeClassName}>
+            {isTrendingUp ? <ChevronUpIcon /> : <ChevronDownIcon />}
+            <span className="text-[12px] font-medium whitespace-nowrap">{badgeContent}</span>
+          </div>
+        )}
+
+        {/* Value */}
+        <div className="break-words overflow-hidden flex-1">
+          <span className="text-[26px] font-medium text-neutral-700">
+            <NumberFlow value={value} format={valueFormat} />
+          </span>
+        </div>
+
+        {/* Trend indicator */}
+        {displayTrendText && (
+          <div className="flex items-center gap-1 text-md mt-auto text-neutral-600">
+            {renderTrendIcon(!!displayTrendText, changePercentage, trendDirection, isTrivialChange)}
+            <span className="break-words flex-1 text-[14px]">{displayTrendText}</span>
+          </div>
+        )}
+      </div>
+    </Card>
+  );
+};
