+import { describe, expect, it } from 'vitest';
+import { getErrorDetails, isErrorWithDetails } from './errorDetails';
+
+describe('errorDetails', () => {
+  it('validates and flattens details', () => {
+    const error = { errors: [{ details: ['one', 'two'] }, { details: ['three'] }] };
+
+    expect(isErrorWithDetails(error)).toBe(true);
+    expect(getErrorDetails(error)).toStrictEqual(['one', 'two', 'three']);
+  });
+
+  it('returns empty array for non-conforming errors', () => {
+    expect(isErrorWithDetails({})).toBe(false);
+    expect(getErrorDetails({ message: 'nope' })).toStrictEqual([]);
+  });
+
+  it('rejects details that are not strings', () => {
+    const error = { errors: [{ details: ['ok', 2] as unknown as string[] }] };
+
+    expect(isErrorWithDetails(error)).toBe(false);
+    expect(getErrorDetails(error)).toStrictEqual([]);
+  });
+});
diff --git a/src/utils/errorDetails.ts b/src/utils/errorDetails.ts
new file mode 100644
index 000000000..fc7650db1
--- /dev/null
+++ b/src/utils/errorDetails.ts
@@ -0,0 +1,32 @@
+type ErrorWithDetails = {
+  errors?: Array<{ details?: unknown }>;
+};
+
+export const isErrorWithDetails = (
+  error: unknown
+): error is { errors: Array<{ details: string[] }> } => {
+  if (!error || typeof error !== 'object') {
+    return false;
+  }
+
+  const errors = (error as ErrorWithDetails).errors;
+  if (!Array.isArray(errors)) {
+    return false;
+  }
+
+  return errors.every((err) => {
+    if (!err || typeof err !== 'object') {
+      return false;
+    }
+    const { details } = err as { details?: unknown };
+    return Array.isArray(details) && details.every((detail) => typeof detail === 'string');
+  });
+};
+
+export const getErrorDetails = (error: unknown): string[] => {
+  if (!isErrorWithDetails(error)) {
+    return [];
+  }
+
+  return error.errors.flatMap((err) => err.details);
+};
